INSERT INTO public.categories (id, name, slug, description, icon, sort_order, created_at) VALUES ('af05cb5e-a803-41af-b387-b29046ae20c6', 'Team Formation', 'team-formation', NULL, NULL, 13, '2026-07-08T04:56:55.320965+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('bb4da8b6-7561-41f1-9e0c-8224d171b31a', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'What is VINS?', 'VINS is the Vicharanashala Internship — an online programme open to anyone who clears our interview. The work is real open-source contribution under a mentor, the certificate is from the Vicharanashala Lab for Education Design at IIT Ropar, and the programme itself is free (we charge nothing). There is no stipend. If you are seeing a yellow VINS panel on your result page, you are selected.', '{"about"}', 2, 0, 0, 1, 0.855333, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T07:32:55.112904+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f1f7c228-1e24-48a9-921a-209ead93b681', '15f28d63-b183-4584-a6ae-d189b419fbea', 'How do I log in to ViBe?', 'Link for the website: https://vibe.vicharanashala.ai/authSign up as a student with the registered mail ID into the ViBe platform.To log in to the ViBe platform, follow the steps below carefully: ``` Log in to the ViBe platform as a student from registered email IDCheck the "Notifications" tab in the Top right side of the Dashboard.Accept the course invite sent for your respective MERN Course. ``` ⚠️ Logging in with a different email ID may result in access issues or missing course visibility.', '{"vibe"}', 1, 0, 0, 1, 0.693147, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T13:05:45.523947+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('1bd1bdd7-21bd-4e87-99be-c4eb0b95b85d', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'What is the Vicharanashala internship?', 'A two-month, full-time engagement at the Vicharanashala Lab, a research lab at IIT Ropar. You will work on a real open-source project under a mentor, after a short training phase tailored to where you already are. The internship is free — we do not charge, and the work is real.', '{"about"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d4b53edd-0496-45d3-aedf-7fd8bf1a6934', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'What are the phases of VINS, and what do the badges mean?', 'VINS is structured as four phases. Each one is marked by a badge — a small token of where you are in the journey. 🥉 Bronze (Phase 1) — a short training period at the start, planned around what you already know. If you arrive already comfortable with the basics, your mentor may skip Bronze and put you straight on to the project. 🥈 Silver (Phase 2) — the main work. You contribute to a real open-source project under a Vicharanashala mentor. Finishing Bronze and Silver completes your internship and earns the certificate. 🥇 Gold (Phase 3) — a recognition awarded during Silver if your contribution stands on its own as a meaningful feature, not just a small fix. 🏆 Platinum (Phase 4) — a standing invitation to come back and visit the lab — a short trip — any time during the year after your internship ends. We help with travel through a small visit stipend. Most interns finish at Bronze + Silver, and that is exactly what the certificate is for. Gold and Platinum are extras you can pick up if your work makes the case for them. Either way, you walk away with a real open-source contribution to your name and a mentor who knows you well.', '{"about"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('27f9d0da-789c-42c4-a177-2605eb01590f', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'Who is the internship for? Are alumni eligible?', 'The internship is for currently-enrolled students at any college or university — undergraduate, postgraduate, or doctoral. The NOC requirement is the practical reflection of this: we ask for institutional consent that you can commit your time to this internship. Candidates who have already graduated and are not currently enrolled in any programme are not eligible for this cycle. If you re-enrol later (higher studies, etc.), you are very welcome to apply again in a future cycle.', '{"about"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('25d75eeb-dcc5-4dcb-99d3-3f0b766661ad', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'Is this the same as IIT Ropar''s official Summer Research Internship?', 'No. Summership 2026 is a VLED Lab initiative. The certificate is issued by the Vicharanashala Lab for Education Design, not centrally by the institute. IIT Ropar runs a separate institutional summer research internship through its own office. Do not represent Summership 2026 as equivalent to that programme.', '{"about"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('33f56f6c-ff97-4ba5-ba43-800070e74373', '40bcbab5-ea36-4ff4-b538-02ffae9aba55', 'I have to attend my class tomorrow/today/some day — can I take leave?', 'Leave is not permitted. If you are also attending classes or exams, you will be relieved from the internship immediately and will need to join the next batch when it starts.', '{"about"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('524d251b-2aef-4eef-93e6-a7cf10d23a8d', '68d7a70e-0267-45c1-a352-720e831eea8f', 'When can I start?', 'You can start any time in 2026 — VINS is flexible on the start date — but there are two things you must hold in mind together, and one strong recommendation. The hard rule. Your internship must finish by 31 December 2026. That date is non-negotiable. Whatever start you pick, your end date (your start + 2 months, with up to 1 month grace) must land on or before 31 December 2026. So while there is no last date to opt in, there is absolutely a last date to finish. The strong recommendation: start as soon as possible. The earlier you join, the more of the May–July main cohort you catch — and three things make starting earlier materially better than starting later: Cohort networking. The batch goes through Bronze together — peer discussions, parallel problem-solving, and lasting connections happen during this window. Later in the year the cohort disperses and late starters are largely solo. TA support is concentrated in May–July. TAs are full-time during this window. After this they return to their own college work and bandwidth is materially thinner. Training rolls out with the cohort, not piecemeal — you get the material with the discussion around it, not as a static document. If starting now is genuinely impossible for you (exams, other unavoidable commitments), you can begin later and still complete and earn the certificate — but be honest with yourself: the cohort effect and support will be lighter, and the December cap means a late start leaves no room for slippage.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('9fa35855-d49e-41c1-b2ba-fa8617884e04', '68d7a70e-0267-45c1-a352-720e831eea8f', 'How long is the internship?', 'Two months from your chosen start date, with an optional one-month grace period if you need it. End must land on or before 31 December 2026.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('a993899b-628b-4c2e-9d7c-fd7f885b779e', '68d7a70e-0267-45c1-a352-720e831eea8f', 'Can I start in July, August or later if I have exams now?', 'Yes — but only if your exams genuinely make an earlier start impossible. Wait until your exams are done, then opt in and start. Do not attempt to juggle this internship with ongoing exams. Make sure your chosen start date plus 2 months (or 3 with grace) lands on or before 31 December 2026.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4acd842b-58fe-4389-bc59-0c3a4c9d291a', '68d7a70e-0267-45c1-a352-720e831eea8f', 'Can I start with the cohort and take a relaxation during my exam window?', 'No. This is not an arrangement we offer. VINS is a full-attention internship — six to ten hours a day, sometimes more. Splitting that with college exams damages both sides: the project loses momentum, the exams suffer, and the mentor invests in someone who can only half-engage. We have seen this fail enough times to be firm. If your exams fall inside the cohort duration, defer your start to after your exams end, opt in then, and run the internship at full attention. The certificate and project pathway are the same. A note on consequences. If we later learn that a candidate was sitting college exams during their internship period, we reserve the right to terminate the internship or withhold the certificate at any time — including after the internship has otherwise been completed.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('cc86923b-e7d4-4ac9-8763-8bdef5a90922', '68d7a70e-0267-45c1-a352-720e831eea8f', 'Can I take leave or get an exemption during the internship for an exam scheduled in June?', 'The attendance rule is firm — the 55-day continuous window is a non-negotiable part of the internship, and we cannot offer an exemption for an exam during this period. The policy exists because split attention genuinely damages both your exam preparation and your internship work.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('e255f13a-e80d-4f17-b500-cef7843b6168', '68d7a70e-0267-45c1-a352-720e831eea8f', 'Are orientation session recordings shared with interns, and can project or group assignments be changed after watching them?', 'Recordings of the sessions will not be provided. However, we may provide access to an abridged version of a talk or session if we consider it important. We do not guarantee this for every session.', '{"timing"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('0def9aad-26e9-44b0-913c-666cbb71c812', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'What dates do I put on the NOC?', 'Default: your chosen start date → your start + 2 months (with up to 1 month grace), ensuring the end date is on or before 31 December 2026. Pick the earliest start date you can realistically make — the May–July summer window is the main cohort. If the NOC will be signed on a specific later date, pick a start date after the signature date.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('735c3a2a-e98a-48f5-aa76-dc6a952f0ad6', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'Who can sign the NOC?', 'Any authorised signatory at your college: HOD, Acting HOD (during holidays), Principal, Dean, Director, or Training & Placement Officer. For dual-degree students, either institution can sign — pick whichever is easier. For IITM BS Online Degree (standalone) students, any officer from the BS office can sign.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('12f216c0-58e0-4d71-88bc-1693cb434620', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'When do I submit the NOC? Is the deadline hard?', 'There is no specific calendar cut-off date by which the NOC must be uploaded — but your internship cannot formally begin until your official institutional NOC has been uploaded and validated by us. So submit your signed NOC as early as possible and join the current summer cohort. If you are on VINS you can technically upload your NOC and start later in the year, but we strongly do not recommend it — by then your mentor may already be busy with other work, you will not get to network properly with the rest of the cohort, and the cohort + TA support that make this internship genuinely good are concentrated during the summer window. Submit early, start as soon as possible, and you will get the full version of the experience.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5086e320-887b-48f9-8d74-9b1fdc78af17', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'What format should I use? Do I need to design it myself?', 'No — we provide a printable NOC format. Once your result is out and you log in to samagama.in, you will see a Download blank NOC button on your dashboard. Take a printout, get it physically signed and stamped by your authorised signatory, scan it, and upload the signed PDF using the Upload signed NOC button (also on the dashboard). You do not need to draft anything yourself, and you do not need college letterhead — the format we provide is the canonical layout.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4a28efa3-c086-4231-8a63-88e25f2751cf', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'What if my college / Program Chair gives me an NOC in their own format?', 'A college''s own NOC format is acceptable, as long as all of the required entries are present on it: The signing authority''s (HOD / Dean / Program Chair / Principal) handwritten signature — this is the most important itemThe signing authority''s name, designation, official email address, and phone number (we cross-check with that person to verify the signature is genuine)Your full name and the internship period (start and end dates)Your signature If your college''s format does not include a place for your signature, sign clearly and prominently anywhere on the document before uploading. With those entries present, you do not need to switch to our printable format. An NOC missing any of them is incomplete and will be returned for correction.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d43f06bd-a2f3-4107-93ba-15530aa7f9a0', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'Does it need to be signed by hand?', 'Yes. Three things are required, all on the NOC format we provide: The authorised signatory''s handwritten signatureThe institutional rubber stamp / seal applied in the designated areaThe signatory''s email address filled in the designated field — we automatically cross-check with that person to verify the signature is genuine Digital signatures are not accepted. The only path is a physically-signed printout uploaded by you from the dashboard (see §3.8).', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('6f6fb84a-6fde-4b99-babb-7808d6a26fbd', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'Can my HOD email the NOC instead of uploading it?', 'No. Your NOC must be uploaded by you, the student, from your dashboard — we no longer accept NOCs sent by email. We previously offered an email-forward path where your HOD emailed the NOC to us. That option has been retired. NOCs emailed to us — whether by you or by your HOD — will not be processed. The only accepted way to submit your NOC is to download the format, get it signed by the appropriate authority at your institution, and upload the signed PDF yourself from your dashboard (see §3.8). If your college gives you a signed NOC in their own format, that is fine (see §3.5) — you still upload it yourself as a PDF.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('04037d1c-3f7a-4ec0-8428-5ba0aaa2ae72', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'How do I download and upload the NOC?', 'Both happen on your dashboard at samagama.in once your result is out. You will see a NOC section with two buttons in three places (all backed by the same endpoints — use whichever is convenient): A compact pill in the dark header bar at the top of every screen.A standalone NOC card on the dashboard, between the Results card and the Talk-to-Yaksha button. A NOC section at the bottom of your full Result message itself. The two buttons: Download blank NOC — saves the printable NOC format PDF.Upload signed NOC (PDF) — opens a file picker; the file must be a PDF of at most 1 MB. Confirmation appears on the same card once the upload is received. The chat surface no longer carries any NOC affordance — please use the dashboard buttons. If you can''t see the buttons, make sure you are logged in as the email that received the result, and that your result has been released.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b77d4261-04cc-4410-9142-13f80b58ca6f', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'What if my NOC is not formally verified?', 'NOC verification takes time — typically anywhere between an hour and one full working day from the moment you upload. Your offer letter is issued automatically once your signed institutional NOC is uploaded and validated — there is no faster route. (The earlier self-declaration / provisional-offer option was retired on 2026-05-27 and is no longer accepted.) Please upload your signed NOC as early as you can so your start is not delayed.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('861c62cf-5d4c-4d3b-9204-c6f3ea69200f', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'Why has my mentor not been assigned yet, or contacted me on day 1?', 'Mentors are not assigned on day 1 of the internship. You will be assigned a mentor when you move on to the project phase of VINS, which comes later in the timeline. Before that, you must complete the mandatory coursework of the Bronze phase (see §1.3). Once coursework is complete and you are placed on a project, your mentor will reach out. If you are looking for a Discord server, please note: we do not run a Discord server. See §6.1 for the official communication channels.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5492f8f1-7fde-4704-8578-2b2ca0f1db0c', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What if I miss the team allocation announcement?', 'All programme updates are posted in the Announcements section on samagama.in. Log in and check regularly during working hours — this is the only channel for official notifications.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('8a3d374c-7ac9-47be-b997-347b73a53feb', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'My online course (Masai, NPTEL, Coursera, etc.) won''t issue an NOC. What do I do?', 'The internship is open only to candidates currently enrolled in a full-time degree programme at a recognised college or university. Online-only courses — Masai Institute, NPTEL / MOOC enrolments, Coursera, Udacity, bootcamps, and similar — do not by themselves make a candidate eligible. If you are concurrently enrolled in a full-time degree programme alongside the online course, please obtain a No Due / No Objection certificate from that college (department, Dean''s office, or Principal) and upload it via the NOC upload flow on your dashboard. If your only current academic engagement is the online course and you are not concurrently enrolled in a full-time degree programme, the internship is not open to you in this cycle. We would warmly welcome you to apply again in a future cycle once you are enrolled in a full-time programme.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('405125db-5940-4b9c-a5d1-4b12846f79f4', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'My HOD/college official wants written confirmation before signing my NOC. What do I show them?', 'Your selection is already confirmed the moment your yellow VINS (or green VISE) result panel appears on your samagama.in dashboard — that is the official confirmation of your selection, and it is what your HOD should sign your NOC on the basis of. There is no separate written confirmation letter or other proof-of-selection document issued before the NOC step — and none can be sent on request. (The selection-confirmation letter and the self-declaration / provisional-offer route have both been discontinued.) Your offer letter is issued only after your signed NOC is uploaded and validated, so it is not available beforehand. If your college will not sign without something in hand, show them your VINS result panel on the dashboard as evidence of selection — that is the confirmation we provide.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('dfa4e24d-9f33-45b3-9b4f-66c095e36978', '802a09d8-706e-41f8-95c7-2b2a0ca774f2', 'Can Prof. Sudarshan Iyengar or a faculty member from IIT Ropar sign my NOC for the internship?', 'Your NOC must be signed by an authorised signatory at the institution where you are enrolled as a student — such as your HOD, Dean, Principal, or Training & Placement Officer. Sudarshan Iyengar is a faculty member at IIT Ropar and is not the authorised signatory for the IIT Ropar/Masai online AIML programme. He cannot sign your NOC in a personal capacity. Regarding eligibility: the internship is open to candidates currently enrolled in a UG/PG/Diploma programme at a recognised college or university. An online-only certification course (even if offered jointly with an IIT) does not meet that requirement on its own. If you are concurrently enrolled in a full-time degree programme elsewhere, please obtain the NOC from the authorised signatory at that institution. If your only current academic enrolment is the IIT Ropar/Masai online programme, you are not eligible for this internship cycle. Please clarify your current enrolment status and we will guide you accordingly.', '{"noc"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('a81144ee-94f0-4c72-ac43-77855e42cf3f', '3cabaf52-f127-4506-851c-7d49246c86c4', 'How do I know I am selected?', 'If you can see your yellow VINS result panel on samagama.in, you are selected. There is no separate selection step or confirmation email.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('9b38e6c3-702d-46b6-9d91-d6378e61bc31', '3cabaf52-f127-4506-851c-7d49246c86c4', 'How do I opt into VINS?', 'Tell Yaksha in the chat: "I want to take up the online internship without stipend." Yaksha will confirm. Opting in is the selection — no separate confirmation email is sent at that stage.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('2d6ea921-3170-4641-a8a2-078611e261b2', '3cabaf52-f127-4506-851c-7d49246c86c4', 'When do I get the offer letter?', 'Your offer letter is issued automatically once you upload your signed institutional NOC (and have confirmed your start and end dates on the dashboard, see §4.5) and we validate it — typically within an hour to one full working day of upload. There is a single offer letter on Vicharanashala letterhead; once your NOC is validated it is the operative offer for your college / employer records. (The earlier self-declaration / provisional-offer "fast path" was retired on 2026-05-27 and is no longer available — a signed institutional NOC is now the only way the offer letter is issued.) The offer letter lives on your dashboard at samagama.in, not in your email. When it is issued, a notification will appear in the Announcements section of samagama.in. Log in and click Download Offer Letter from the Offer Letter card on your dashboard. If you do not see it, do a hard refresh and log back in — or raise #escalate in Yaksha chat.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b197725b-df64-4e2a-9632-3295f5ce3b50', '3cabaf52-f127-4506-851c-7d49246c86c4', 'Will I get a certificate?', 'Yes — every intern who completes the internship gets a certificate from Vicharanashala, IIT Ropar. The internship is genuinely demanding; candidates who drop out mid-way do not get a certificate. Finishing means something, because the bar is high.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('1fa04c2e-bf9e-430b-ad68-4034793297cd', '3cabaf52-f127-4506-851c-7d49246c86c4', 'How do I confirm my internship dates?', 'Once you have opted into VINS in the chat with Yaksha (see §4.2), log in to samagama.in. On the dashboard, you will see a yellow card titled "🗓️ Confirm your internship dates". The two date pickers pre-fill with sensible defaults for the current cohort. If those work for you, hit "Save dates". Otherwise edit them to your earliest realistic start — your end must be on or before 31 December 2026. A green confirmation appears once saved. You can edit any time from the same card. Order doesn''t matter. You can save your dates before or after uploading your NOC — both paths work. The dates you enter must match the internship period your HOD signs off on in your NOC. If you need to change the period later, edit the dates on the same card and upload a fresh NOC matching the new period.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('2c8b1ec6-131e-4391-acf9-92c75828d1aa', '3cabaf52-f127-4506-851c-7d49246c86c4', 'I am a minor/major in AI student, can I join the programme? I don''t need a NOC as I am from IIT Ropar', 'Minor/Major in AI course from IIT Ropar is a certification course and there will be a different track of internship equivalent to them. Kindly write to us separately for this. For you to be part of this internship programme you should be a registered student in a UG/PG programme with some university. This internship is exclusively meant for the students only and not for working professionals.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('422a889f-3083-40e4-ad35-ed5ed460a138', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'How do I use it day to day?', 'Simple: Open your Rosetta Google Doc.Scroll to the entry for today''s day number.Fill in the date at the top of the entry.Read the thinking routine name and its one-line description.Answer the three prompts in the writing boxes below.Close it and get on with your day. That is it. It should take between 10 and 20 minutes. It is not an essay. It is not a report. It is a journal.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('80ec99da-225e-4151-94f9-156c33747272', '3cabaf52-f127-4506-851c-7d49246c86c4', 'How do I accept the offer letter?', 'Acceptance happens entirely on your dashboard at samagama.in — there is no email reply, and nothing to paste or post. The Offer Letter card guides you through three steps, and your offer is recorded as accepted only once all three are complete. Please finish them within 5 days of your offer being issued: Offer letter — download your offer letter, sign the *Acceptance of Offer* block at the bottom of it, and upload the signed PDF on the card. Terms & Conditions (Participation Agreement) — read each section and tick the box to confirm you have understood it. Honor Code — download the Honor Code, sign the last page, and upload the signed PDF. Each PDF upload is capped at 1 MB; to correct a file, just upload a new copy — the latest replaces the previous one. The card updates as you complete each step and shows your offer as accepted once all three are done. There is no acceptance email to send and no statement to type. If you have completed all three steps and the card has not updated after a refresh, log in to samagama.in and type #escalate in the Yaksha chat and we will check.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('241011bd-f13b-4419-99fa-3427b68efc69', '3cabaf52-f127-4506-851c-7d49246c86c4', 'Can I change my internship dates?', 'Before the offer letter is issued: yes — open the Confirm Internship Dates card on your dashboard and edit the dates at any time. Your end date must be on or before 31 December 2026. After the offer letter is issued: no. Dates are final and will not be changed. If the confirmed dates do not work for you, please follow our LinkedIn page for announcements about future cohorts: linkedin.com/company/vicharanashala If you updated your NOC to reflect new dates before the offer letter was issued, upload the revised NOC via the dashboard.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('a978b0cb-6ee2-4cb4-ba09-9da5a9ac9eb3', '3cabaf52-f127-4506-851c-7d49246c86c4', 'My NOC is not ready but my start date is approaching. What do I do?', 'Get your signed institutional NOC uploaded as soon as you can. Your start date cannot be honoured until your official NOC is uploaded and validated by us — the internship formally begins only after the NOC is validated. If your NOC is not in by your chosen start date, your start simply shifts to whenever it is validated. (The earlier self-declaration / provisional-offer option was retired on 2026-05-27 and is no longer accepted, so a signed institutional NOC is the only way forward.)', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('3c906016-47d9-41b2-b030-6c957dea5e6e', '3cabaf52-f127-4506-851c-7d49246c86c4', 'When does my internship actually begin? Will I receive a notification on the day?', 'Your internship begins on the start date you confirmed on the dashboard — the same date printed on your offer letter — provided your official institutional NOC has been uploaded and validated by us by then. If your validated NOC is not yet in on your start date, your start shifts to the day it is validated. There is no separate "your internship has begun" email, chat message, or dashboard notification on the day itself; the start date is the start date. On the morning of your start date, log in to samagama.in. Yaksha will guide you through the Day-1 steps of the Bronze phase. If your dashboard appears unchanged on that morning, do a hard refresh and re-login. If it still looks the same, type #escalate in the chat and we will look at your specific case. You can review or change your confirmed dates via the Confirm Internship Dates card on your dashboard (see §4.5 to set, §4.8 for date-change rules).', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('2eeed5ed-d305-40bf-9c48-066b1cd523c1', '3cabaf52-f127-4506-851c-7d49246c86c4', 'Can I switch from VINS (online) to VISE (offline) after being selected?', 'The two tracks are finalised at the interview stage, and we do not move candidates between them. VISE has a fixed on-campus capacity planned around mentor bandwidth, hostel availability, and stipend allocation — once the shortlist is set, it stays set. VINS is not a consolation track. The project, the mentor, and the certificate are the same as VISE — what differs is the mode (online) and the absence of a fellowship. Many interns find the online format more effective. Your best path forward is to confirm your VINS start dates and get your NOC uploaded — you''re already in a strong position.', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('2018f82f-e0ad-41ad-a058-3370dc6cef13', '3cabaf52-f127-4506-851c-7d49246c86c4', 'Can I change my internship dates after the offer letter?', 'No. Once your offer letter has been issued, the dates you confirmed are final. They will not be changed at this stage. If the confirmed dates do not work for you, please follow our LinkedIn page for announcements about future cohorts: linkedin.com/company/vicharanashala', '{"selection"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('74c2c1e4-38db-44c0-b179-b52aead7f8a6', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'What will I work on?', 'A real open-source project from Vicharanashala''s portfolio — assigned based on your background and the lab''s current needs. Areas range across AI/ML, web development, NLP, computer vision, agriculture-tech (Annam.AI), education-tech (ViBe), and open-source infrastructure. We do not pre-publish the exact problem; you choose to join knowing the lab will assign the project.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('e7d15244-4094-41e5-b7aa-821cfbed8d4b', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'How many hours per day?', 'Plan for 6 to 10 hours a day, sometimes more during the build phase. This is a full-time internship for the two-month window. Most candidates who drop out are juggling something else — VINS expects your full attention.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('51f49e9e-dacf-4c10-8a40-63207a20a9ff', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'Who is my mentor?', 'You will work with the lab''s research and engineering team. The exact mentor depends on the project. The model is fluid — you will get help from a senior researcher one day, a peer the next, and someone else for a different question. That is how real open-source work happens.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('93e9fbc0-acdb-4cb2-a4ad-0bd2fc5bf9b8', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'Is there a stipend?', 'No. The internship is unpaid. Stellar performers may be recognised with a discretionary stipend at the lab''s option, but this is not promised or expected.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b135ce4b-8088-4610-bb1e-ba8b96d1ed41', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'Do I need my own laptop? Should I preload any software?', 'Yes — a personal laptop is required. We prefer that you bring a laptop running Linux or macOS. If you use Windows, please install a terminal that can SSH and run Unix-style commands — for example, Windows Subsystem for Linux (WSL) is a clean choice; a tool such as PuTTY also works. You will be SSH-ing into machines and using the command line as part of the work. We do not maintain a fixed software-preload list — your mentor will guide you on the specific tools needed once your project is assigned.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d5f85f77-3566-4027-a2f9-f6d1b8f2c6e9', '3c59ee09-2042-4898-ba28-50a8837cec53', 'Can we register and start the vibe courses before our internship date formally starts?', 'You will receive the viBE course link only after your internship starts. You can register and start the viBE courses related to the internship only after your internship formally starts.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7f034de6-9cb3-4c27-9c81-4049b36dc778', '5107fef9-1415-4a13-9f32-7231d7135ef3', 'I am using a different email on GitHub / Zoom / the learning platform. Is that okay?', 'No. Your registered email is your sole identifier across all programme platforms. Progress tracking, mentor assignment, and certificate issuance are all tied to it. Mismatches between platforms cannot be retroactively corrected — ensure you use your registered email everywhere from day one.', '{"work"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('e914fcc5-ef03-4925-8485-36f8cdd66d8a', 'b05dc927-6212-4be1-a8a2-dad8643107f0', 'What are the official communication channels?', 'Official channels only. The Announcements section on samagama.in is how we notify you — all programme notifications are posted there (we no longer send notifications by email). Log in and check it regularly during working hours; sessions are announced at least 1 hour before they begin. To get help with a question or problem, follow this order: Yaksha chat on samagama.in. This is the first place to bring any question or problem — start here and let Yaksha help. Discussion forum. If Yaksha cannot resolve your matter, take it to the discussion forum. The link was sent to you in your sign-up (registration) email when you first created your account on samagama.in, and is also posted in the Announcements section. This is where you troubleshoot and discuss with your peers and the team. Escalate to a human. Only if the discussion forum does not resolve your issue — return to Yaksha chat and use #escalate to reach Sudarshan Iyengar and the team. Email to internship@vicharanashala.ai — an absolute last resort, only after all of the above have not resolved your question. WhatsApp support is cancelled. There is no WhatsApp troubleshooting group. Not being on WhatsApp does not put you at any disadvantage — all information goes through the channels above. Unofficial groups are strictly prohibited. Creating, joining, or operating any WhatsApp group, Telegram channel, Discord server, or any other peer-coordinated space involving interns or a subset of interns — or contacting another intern through their personal phone number — is against the code of conduct. Any complaint or report of this will lead to the immediate termination of your internship. You may connect with fellow interns over LinkedIn and email.', '{"code"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('23492cbf-beb9-4039-a801-b6b7294620e1', '6630013a-6a82-4b2f-8b78-0c918d5b1225', 'My interview is not marked as complete on the dashboard — what do I do?', 'A data-sync issue sometimes occurs where the chat session closes but the interview record doesn''t update to "completed." The team will check your record and manually mark it as complete if needed. You will be unblocked within 1–2 hours. Apologies for the inconvenience. If you dont hear from us and if your interview continues to be marked incomplete please write to us on internship@vicharanashala.ai', '{"interviews"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('c3c2e542-7652-4e3c-ac1b-38e620e8270c', 'ea5de555-fce7-4c08-990d-93b572bebf67', 'Does Vicharanashala send a grade report or evaluation to my university for internship credit?', 'Vicharanashala does not send formal evaluation or grade reports to universities — that process is between you and your college. The certificate issued upon completion is the document you can submit to your college or placement office for credit. Whether your college accepts it and how they translate it into a grade is their decision. If your college specifically requires a structured evaluation form or a report on your performance, raise that with them directly — we can provide the certificate and, if earned, a letter of recommendation, but we don''t have a process for sending grade reports to universities.', '{"certificate"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('60056f5d-c006-4040-b26a-03d827599e7b', 'ea5de555-fce7-4c08-990d-93b572bebf67', 'Does the Vicharanashala internship certificate specify whether it was completed online or offline ?', 'The certificate you receive on completing the internship is the same for both tracks. It is issued by Vicharanashala, IIT Ropar, and does not specify whether you completed it online or on campus. The certificate records only that you completed the internship; the mode is not called out separately on the document.', '{"certificate"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('ad94e97e-728f-4b1d-b736-8ec6b8dbcd31', 'ea5de555-fce7-4c08-990d-93b572bebf67', 'Will the completion certificate be a physical hardcopy or an e-certificate?', 'The completion certificate is issued as an e-certificate — you download it from your dashboard on samagama.in after completing both Bronze and Silver. We do not print and mail physical copies. The certificate is digitally signed and authentic, so it cannot be duplicated. It can also be verified from our database using the number on the certificate.', '{"certificate"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('04ec56d8-d2fd-4716-9925-ab829360be5f', 'ea5de555-fce7-4c08-990d-93b572bebf67', 'Is there a WhatsApp group for candidates during the internship?', 'No. See §6.1 for the official communication channels.', '{"certificate"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('598925af-20de-443a-b554-fcafb9e0ae41', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'What is Rosetta?', 'Rosetta is your internship journal — a 65-day document, one entry per day, every day, for the full duration of Summership 2026. You write in it daily, keep it privately, and submit it at the end of the internship as one of your completion requirements. The name comes from the Rosetta Stone — discovered in 1799, it carried the same text in three scripts and became the key to decoding an ancient language that had been silent for centuries. Not because it was grand, but because it was honest and consistent. That is what this journal is meant to be for you. Sixty-five days of honest writing will become the key to understanding your own experience — what you learned, where you struggled, what shifted in you.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('0da133c3-9a95-4037-8fd1-9a732ec618ab', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'Why does this exist? Is it just busywork?', 'No. It exists for two reasons. For you: Most people go through an intense experience and carry it without processing it. They finish and cannot articulate what they actually learned, what changed in them, or what they would do differently. The journal builds that articulation, one day at a time. Students who reflect regularly during a programme consistently get more out of it than those who do not — not because they work harder, but because they understand what they are doing and why. For us: When you submit Rosetta at the end, it gives us qualitative insight into your experience that no survey or evaluation can capture. We use it to understand what worked, what did not, and how to make the programme better for the next cohort. Your honest voice matters to that process.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('1eb270a4-d4c1-40ad-85b8-d7df398c4231', '3c59ee09-2042-4898-ba28-50a8837cec53', 'What are Spurti Points (SP)? Do they affect my internship?', 'Spurti Points are a platform feature that tracks your engagement with the programme. They are currently in an early beta phase — not used for any decisions about your standing. See Section 11 for the full SP FAQ.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b93b959e-9675-49be-b6b2-1b2b27df20cb', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'We selected Project X as our top priority but were assigned Project Y. Can we change it?', 'No. Project assignments are final and cannot be changed. Allocation is done to ensure balanced distribution across projects.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('23146890-a50c-44c1-9a90-26bf5c56e441', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'What is a "thinking routine"?', 'Each day in Rosetta has a thinking routine — a short framework that gives your reflection a specific shape. Instead of staring at a blank page and writing "today was good," the routine gives you a specific lens. Examples: 3-2-1 — 3 things you engaged with, 2 questions on your mind, 1 surprise.Muddy / Clear — what is sharp, and what is still foggy.What? So What? Now What? — separate facts from meaning from action. The routines rotate across the 65 days so the journal does not feel repetitive or mechanical. Some will feel easy. Some will make you stop and actually think. That is the point. You do not need to research the routine or prepare for it. Just read the description at the top of each day''s entry and write.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('24bfbf0b-cbea-4d94-853b-26fcd3d6df02', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'How do I get my Rosetta journal?', 'The Rosetta template is here: Rosetta Journal — Summership 2026 Open the link, go to File → Make a copy, save it to your own Google Drive, and rename it Rosetta — [Your Name] — Summership 2026. That copy is yours for the full duration of your internship. Do not write in the shared template. Always work in your own copy.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f96cb100-4c0e-4161-9abe-dd2dc1e933d7', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'How long should each entry be?', 'There is no minimum or maximum word count. A good entry is one that is honest and specific. Three to five sentences per prompt is usually enough. If you find yourself writing more because something genuinely needs unpacking, write more. If a day was quiet and you genuinely only have two sentences, that is fine too. What is not acceptable: one-word answers, copy-pasted text, vague non-answers like "today was productive," or anything that reads like it was generated by an AI.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5618c858-c50e-43fe-8cd4-8f09d05885ed', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'What is the one rule?', 'Write what is true. Not what sounds impressive. Not what you think we want to read. Not a polished summary of the day. If you hated today, write that. If you are confused and frustrated, write that. If something clicked and you are genuinely excited, write that. We will know immediately if an entry reads like an LLM wrote it. Do not do that. The journal only counts as a completion requirement if it is genuinely yours — in your voice, from your actual experience.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7ad45d8f-149c-4163-b7bc-20e379a9c7b3', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'Can I use ChatGPT or any AI tool to write my entries?', 'No. This is the one firm rule of Rosetta. The journal is a record of your thinking, not a demonstration of what an AI can produce on your behalf. Entries that read as AI-generated will not be counted toward your completion requirement. If your entire journal reads this way, the journal will not be accepted. Use AI tools for your technical work if that is permitted in the programme. Do not use them here.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7f8ff85a-878c-4d05-8519-5aab3d512471', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'What if I miss a day?', 'Fill it in as soon as you can. Write the actual date you are filling it in, not the date of the missed entry. Be honest in the entry about the fact that you are writing it late and why. Do not leave entries blank. A late honest entry is always better than no entry. If you find yourself consistently missing entries, that is worth paying attention to. It usually means something else is going wrong. Use Yaksha in chat, or reach out to your scholar.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f4dc0d63-7257-4e28-a2a1-bc5239f83349', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'Will anyone read my journal during the internship?', 'No. We will not access your journal during the 65 days. You write it, you keep it, it is yours. The only time we read it is after you submit it at the end of the internship. This is intentional — we want you to write freely, without feeling observed. The journal is only useful if it is honest, and it is only honest if you are not performing for an audience.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d6177c65-8a06-48a7-a587-79ca286a7db4', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'Can the prompts change mid-internship?', 'Occasionally we may update a prompt for a specific day based on what is happening in the cohort — a major milestone, a collective challenge, or something the team wants to address directly. When this happens, we will announce it in the Announcements section on samagama.in before that day begins. Check the Announcements section before filling any entry where a change has been announced. If no announcement has been made, use the prompt as written in your document.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('304c7631-d8a1-4654-96bb-a1fc20a54f3c', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'How do I submit Rosetta at the end?', 'On or before Day 65, share your Rosetta Google Doc with the programme coordinator''s email address (shared during wrap-up week). Set the sharing permission to Viewer. Make sure: Your name is in the document title — Rosetta — [Your Name] — Summership 2026.All 65 entries have been filled in.Your cover page has your name, product, and team filled in. Rosetta submission is one of the required criteria for receiving your internship certificate. An incomplete or AI-generated journal will not be accepted.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b16dd707-a0de-497b-a848-7111946288c4', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'I have a question about Rosetta that is not answered here. What do I do?', 'Ask Yaksha first. If Yaksha cannot answer it, escalate to your programme coordinator. Do not sit on a question — the journal works best when you start it right.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4b42e1b5-d349-4d44-a257-bf2532f29be5', '776f35e1-de12-4496-a718-e4a2a8e2d38f', 'My college requires a written confirmation that the internship is self-paced and will not clash with college classes — what document can I share with them?', 'This is not a self paced internship, but a very rigorous one which is time demanding. It is not permitted for one to be part of any other activity during this period.', '{"rosetta"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('40be7616-0af8-4105-b19a-0c98dcc753a3', '3c59ee09-2042-4898-ba28-50a8837cec53', 'What are the attendance and participation rules?', 'Attendance and participation are tracked strictly, and all of the following are measured continuously over a rolling window of the last 5 working days: Live-session attendance — at least 85%. You must be present for at least 85% of the total Zoom meeting time.Live participation — at least 85%. You must respond to the in-session polls and quizzes at least 85% of the times they are run.Quizzes — attempted, and passed. Every quiz must be attempted, and your pass percentage must be at least 50%. Because this is a rolling 5-working-day measure, it reflects your recent engagement, not a one-time average. If any one of these three falls below its threshold, you will be excused from the current batch and moved to the next batch. This is not a penalty — it simply means you rejoin in a later batch where you can give the programme the full attention it needs.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('6cfde98d-8db6-499f-b146-2348d59b7cc8', '3c59ee09-2042-4898-ba28-50a8837cec53', 'I''ve already completed a course (Vinternship, Pinternship, MERN, or AI) with you in an earlier cohort — am I exempt from repeating it?', 'Yes. If you completed the Vinternship, Pinternship, MERN, or AI course with us in an earlier cohort, you don''t have to repeat it. Submit the exemption form and we''ll exempt you from that course. What counts as "completed"? A course is treated as complete when your ViBe progress is above 95%. We''ve set the bar just below 100% so you''re not chasing the last percentage point. We verify against your ViBe record before confirming. My progress is below 95% — can I still be exempted? No. Below 95% you''ll need to finish the remaining portion on ViBe. Once you cross 95%, you''re covered. I completed it somewhere else, not on ViBe with VLED — does that count? No. This exemption is only for courses you completed with us. If you''re a first-timer confident in your fundamentals, the viva route is a separate option — check the coursework email for details. How will I know my exemption is approved? We verify submissions against ViBe and confirm on your dashboard. No action is needed from you after submitting. Exemption form: https://forms.gle/RWt1v22yVePyZXD79 > Note: Even if you''re exempted from a course, live sessions and stand-ups remain mandatory for everyone, regardless of exemption status. No exceptions.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5aa71d95-cdd2-452d-a9de-5265c9500c60', '3c59ee09-2042-4898-ba28-50a8837cec53', 'How do I register for the AI Fundamentals course on Vibe?', 'Follow these steps: Click the AI Fundamentals registration link posted in the Announcements section on samagama.in at Phase 1 launch.You''ll be redirected to the Vibe sign-in page. If you don''t have a Vibe account yet, create one using the same Gmail you used to register on Samagama.Log in with your credentials.After logging in, open the course registration link again in your browser — the second click after login is what enrols you.Complete the brief registration form and submit.The course will appear instantly on your Vibe dashboard, ready to watch.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7983f3a4-f856-429b-b027-73e6e0592589', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can a team be dissolved and reformed?', 'No. Once finalized, teams are locked and cannot be dissolved.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('8e745d85-2861-49a1-9488-dc7a80df0d80', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What happens if I drop out of the internship?', 'Your team will be adjusted accordingly, and the remaining members may continue as a team of three or receive a replacement.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('3c6cca41-5c07-4880-b123-0b312f46b199', '3c59ee09-2042-4898-ba28-50a8837cec53', 'I registered on Vibe with a different email than my Samagama email — is that OK?', 'Please use the same email on both platforms so we can match your Phase 1 progress to your internship record. The one exception: Vibe requires a Gmail address for signup. If the email you used on Samagama is not Gmail (e.g. a college email like @xyz.ac.in, @ds.study.iitm.ac.in), you may use any Gmail of yours to register on Vibe. In that case, tell Yaksha in your Samagama chat using the tag: `` #vibe-email your-gmail@gmail.com `` so we can link the records.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('79841b5a-6711-47ca-84a0-1abb48bfdcd5', '3c59ee09-2042-4898-ba28-50a8837cec53', 'Are live sessions mandatory if I''m on the viva route?', 'Yes — live sessions are mandatory for every intern, regardless of path. Whether you''re on the coursework track, MERN-exempt (returning intern), or have cleared the viva and moved to Phase 2, you''re expected to attend every live session. The exchange of knowledge across our cohort — diverse streams, varying levels of experience — is something self-paced study cannot replicate.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('89ba116e-629e-4872-9fdc-e55740f994a7', '3c59ee09-2042-4898-ba28-50a8837cec53', 'When and how do I get the Zoom link for the kickoff meeting?', 'The kickoff orientation is held for the main summer cohort only — i.e., candidates starting at the opening of the May–July window. The Zoom link is delivered through two channels: Email to your registered samagama.in address.Your Yaksha chat portal — log in to samagama.in, open the chat, and the link is shown there. If your start date is later (mid-summer or beyond), there is no separate kickoff event for you. See §2.1 for the trade-offs that come with a later start. If you cannot register with the Zoom link or have not received it, log in to samagama.in and type #escalate in the chat with Yaksha — we will look at your specific case.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4553fad8-bb7f-4a64-911e-e89762828e5a', '3c59ee09-2042-4898-ba28-50a8837cec53', 'How do I get the link for the daily Zoom standups? Are they mandatory?', 'Daily Zoom standup links are posted in the Announcements section on your samagama.in dashboard — look for the announcement bell at the top of the page. You are expected to check it daily before the session. Session links are posted at least 1 hour before they begin. We do not send separate emails for daily standups. The announcement on your dashboard is the only delivery channel for the daily link. Attending the daily standups is mandatory for all interns. This is a full-time summer internship programme, and the daily standup is the primary touchpoint where progress, blockers, and the day''s plan are communicated. Missing standups is treated as missing work. Attendance and participation are tracked against strict thresholds — see §10.10. About the kickoff orientation. The kickoff orientation was held for the recommended 15 May cohort (see §10.5). Session recordings are not shared with interns who join late — see §2.6. If you joined late, you are expected to complete the orientation through a special proctored catch-up path on ViBe. The catch-up is entirely proctored and includes quizzes that check whether you have understood the content of the orientation session. Completing this catch-up is mandatory for late starters before participating in the regular standups.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('1139fe36-b2b6-490c-ac1a-6e6116efa8d6', '3c59ee09-2042-4898-ba28-50a8837cec53', 'How do I provide my Zoom ID, and why does it matter?', 'On your dashboard, just before "Start the internship," you''ll see a step called "Provide your Zoom ID." Enter the exact email address linked to your Zoom account — the one you use (or will use) to join the daily live sessions — and save it. This matters because we match your live-session attendance and participation using this email. If the Zoom ID you provide doesn''t match the email you actually join Zoom with, your attendance won''t be credited to you. So enter it carefully and be sure it is genuinely your Zoom account''s email.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('eb2451dd-7ce5-4400-ae5f-78c21089d5e6', '3c59ee09-2042-4898-ba28-50a8837cec53', 'I saved the wrong Zoom ID — can I change it?', 'Once saved, your Zoom ID is final and cannot be changed by you — please double-check before you submit. If you are certain you entered the wrong email, log in and tell us in the chat (type #escalate) with your correct Zoom email, and our team will review and correct it for you.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('a2712e1a-5119-4d08-9f94-b1819d04b310', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What should I do if I face issues within my team?', 'Report any concerns immediately to your assigned scholar/mentor. Maintaining a safe and respectful environment is a priority.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('6e28c8e1-7f50-4a20-9265-d1ab6de6233d', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'What happens if I fall below the required participation level?', 'If any one of the three participation requirements slips below the mark across your most recent five working days, you will be moved from the current batch into a later batch. This is not a termination or an excusal from the programme. It is a practical step so you can rejoin when you are able to give the programme your full attention. To rejoin, you must upload revised documents reflecting your new internship dates: Update your internship dates on the dashboard to match your new batch window.Upload a fresh NOC from your HOD covering the revised period — the dates on the NOC must match the dates on your dashboard exactly. Your previous NOC and confirmed dates are tied to the batch you were excused from and cannot be carried forward. A new offer letter will be issued once your revised documents are verified.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('8f9153c6-af52-4ada-86a4-badc15cbaf3d', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Will we get time to get to know our teammates before Phase 2?', 'Yes. There is typically a buffer period before Phase 2 where teams can connect and prepare.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('16de32b3-6b2c-43f6-812b-b10cdc563dfd', '3c59ee09-2042-4898-ba28-50a8837cec53', 'What are the live-session (Zoom) participation and conduct rules?', 'Treat every live session as a professional classroom. The following rules apply, and repeated non-compliance may result in removal from a session. Video & visibility Keep your video on at all times unless explicitly permitted otherwise — participants with video off will be removed.Your face must be clearly visible — well-lit, centred in frame, and not rotated or partially cut off. A forehead-only view, poor lighting, or a sideways angle are not acceptable.Do not join from a mobile phone. Use a laptop or desktop. Audio & environment Test your microphone and video using the platform''s audio-test feature before the session begins — especially if you plan to speak.Be in a reasonably quiet, well-lit space so you can be seen clearly and participate when called upon. Conduct & attire Dress code: business casuals or neat Indian casuals. Clothing inappropriate for a professional or classroom setting is not allowed.No multitasking. Talking on the phone or with people nearby, and any form of distraction or disengagement, may result in removal. Display name & profile picture Display your full name — first and last. Nicknames or partial names are not acceptable.A professional, clearly identifiable profile picture is strongly recommended. This rule is enforced starting the next session (you have until then to update your display name and picture).Use your professional email account to join wherever applicable. Breaks & reconnection For a short break (e.g. a restroom break), indicate "BRB" (Be Right Back) and return promptly. Prolonged absence may result in a permanent ban.Breaks are provided periodically — manage personal needs during them and avoid leaving during instructional segments.If your internet drops and you are moved to the waiting room, you will not be re-admitted. Ensure you have a stable connection — and ideally a backup — before joining. Waiting room Do not call or message the Core Team for re-admission from the waiting room — doing so will result in an SP deduction. Speaking effectively Keep responses concise — aim for two to three sentences. Rehearse before unmuting, and always test your mic and video beforehand if you plan to speak. Grounds for removal or a permanent ban: video off, joining from mobile, poor visibility, unprofessional attire, disengagement, extended unexplained absence, non-compliance with display-name/picture rules, or repeated violations of session guidelines.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('3e779737-6ab5-485c-90f1-1595fd97c60a', '3c59ee09-2042-4898-ba28-50a8837cec53', 'I got "Failed to submit poll. Error: 100035000" during a session — what does it mean, and will I lose poll credit?', 'This error appears when the poll closed before your response was submitted — either the timer ran out or there was a brief lag between your client and the host. What to do during the session: Do not panic or leave the meeting.If the poll window is still visible on your screen, wait a few seconds and try submitting again.If the error persists and the poll has already closed, note the time and session date — you will need this when you report it. To reduce the chance of this happening: Submit your response as soon as the poll appears — do not wait until the last moment.Stay attentive throughout the session so you do not miss a poll opening.Keep a backup internet connection ready (e.g., mobile hotspot) in case your primary connection drops.Keep your Zoom app updated to the latest version before each session.Use the Zoom desktop or mobile app, not the browser — browser-based Zoom is significantly less reliable for polls.', '{"phase"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('df80d6e9-c7b4-424d-af44-4c67b7e4024e', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'What are Spurti Points?', 'Spurti Points, or SP, are a points layer on the platform that reflects your overall engagement with the programme. Think of SP as an indicator of your engagement — nothing more. It is not a score that defines you as a student or determines your future in the programme.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('fc8415d2-5d18-4520-9dbb-ba885a9f1432', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'Is SP a finished system?', 'No. Spurti Points are still being actively built and refined. SP is best understood as a work in progress rather than a finalised grading or evaluation system. The rules and calculations may evolve as the programme develops.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('65db6b45-19c6-4b36-8859-87b80a22e9df', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'How much importance should I give to my SP number?', 'Please do not read too much into the number. SP is an early beta feature. It is meant to give you a broad sense of your engagement, not to measure your performance or determine outcomes.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5053076f-a1d1-4758-8b15-348996c4cf10', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'Can I be terminated or excused because of low SP?', 'No. The programme team will not terminate, excuse, or take any decision about any intern on the basis of Spurti Points alone. SP is not used as a basis for such decisions.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5e66637b-14be-4a97-b658-f7281f0d6992', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'What if my SP shows as zero or even negative?', 'There is genuinely no cause for concern. A zero or negative SP balance does not mean you are in trouble with the programme. Because SP is in an early beta phase, the number may not always reflect your actual effort or attendance accurately.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('85979ffc-c7d1-4440-bc43-e1547f49f951', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'Does a higher SP bring any benefits?', 'Yes, in a positive way. Interns who build up higher Spurti Points may, from time to time, become eligible for small perks or recognition from the programme team. Think of a higher SP as a pleasant upside to aim for. SP is not used to punish you for a low number or to decide your standing — the one exception is that a mentor may deduct SP for clearly non-compliant behaviour (for example, disrupting a live session or ignoring session conduct rules). That is a deliberate response to conduct, not the same as the beta number simply being low.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7bfb7d83-7d85-4fba-b69f-1fddbde1e4ef', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'If SP does not determine outcomes, what does?', 'Your attendance and live participation are what the programme watches closely and tracks strictly. A low SP number is not a cue to ease off. The programme has clear participation requirements that are monitored independently of SP (see §10.10 for the exact thresholds).', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f61e7c43-6929-44bd-9217-69d40281f7f8', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'How will I know who my mentor is?', 'Your mentor will be the scholar assigned to the project your team is working on.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('38840cab-4d33-4ee1-8937-212a83142166', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'What are the participation requirements tracked strictly?', 'Looking at your most recent five working days on a rolling basis, every intern is expected to meet all three of the following: Stay present for at least 85% of the total live Zoom session time.Respond to at least 85% of the polls and quizzes run during the sessions.Attempt every quiz and clear each with a score of at least 50%. All three requirements apply simultaneously. Falling short on even one of them counts.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('a82d2439-c7e8-44d1-ba97-1486bf67bcec', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'What does "rolling basis" mean?', 'The programme does not look at a single average across the entire duration. Instead, it looks at your most recent five working days at any given point in time. As each new working day passes, the oldest day drops out and the newest day is added. This means your recent, consistent engagement is what counts — not a strong performance in one week followed by long absences. The window keeps moving forward.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('27d8f004-563d-4d43-a939-45d48d5a7654', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can I switch teams if there are conflicts?', 'Team switches are not allowed except in exceptional, admin-approved cases involving serious concerns.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('acdabf05-e868-408c-a6b7-09e42194a6e8', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Will team performance affect individual evaluation?', 'Yes. While some components may be individual, team deliverables are a key part of evaluation.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('8947ffec-0eb1-48fe-b76e-a7f1d6ccbc23', 'a0ab2606-c63c-4323-bfe5-fb1e1aaad46c', 'How are Spurti Points calculated?', 'Every intern starts with a base of 100 SP credited on their official internship start date. SP is then earned through two live-session activities — attendance and poll participation — scored independently for every mandatory morning session: A. Attendance Time present (% of session window)SP earned90% or more+10 SP 75% – 89%+5 SP 50% – 74%+3 SP Below 50%0 SP B. Poll participation Polls answered (% of polls launched)SP earned90% or more+10 SP 75% – 89%+5 SP 50% – 74%+3 SP Below 50%0 SP A few things to note: Both A and B are scored per session and summed across all mandatory sessions attended since your start date.There is no penalty for absence — missing a session earns 0 for that day, not a deduction.Only mandatory morning standup / orientation sessions count. Breakouts, weekend specials, and evening sessions do not contribute to A or B.SP is updated daily. You can see your current balance and a full transaction history on the portal at samagama.in. Important: SP is a reward and recognition feature — it is not used by the programme team to judge your engagement, and it plays no role in excusal decisions. Excusal is determined from raw Zoom attendance logs, independently of SP. A low or zero SP number has no bearing on your standing in the programme.', '{"spurti"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('3ccf78e5-a4aa-4525-9725-4753de7e2a34', '2bc8d5cf-04b8-43d4-b0ae-27685043e8cb', 'I''m unable to type in the chat after clicking ''Interact with Yaksha'' — what should I do?', 'The chat input is only active after you have clicked the "Interact with Yaksha" button. If you are still unable to type, scroll up to the top of the page — the button may be above the visible area. Click it once, and the chat field will become active.', '{"yaksha"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5c11fa0c-d2c8-40f2-9594-2ac19e9f5dce', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Invite accepted but shows "No course enrolled"?', 'If you see "No course enrolled": Make sure you are logged in with the correct registered email ID.Check if your college email has multiple aliases and try the correct one.Log out and log in again once.Use personal wifi instead of college wifi as there might be some network restrictions of access.If the issue continues, please follow these steps: Step 1: Allow Third-Party Cookies Enable Cookies in Chrome: Open chrome://settings/cookies. Turn OFF "Block third-party cookies" and turn ON "Allow all cookies."Add Site Exception: Scroll to "Sites that can always use cookies" and click "Add." Paste .vicharanashala.ai and ensure "Including third-party cookies"* is enabled.Restart browser. Step 2: Fix DNS (Most Important) Change your laptop DNS to Google DNS.Go to: Control Panel → Network → Active Network → Properties → IPv4.Shortcut: Win + R → ncpa.cpl → right-click properties.Set Preferred DNS to 8.8.8.8 and Alternate DNS to 8.8.4.4.Save. Step 3: Flush Old DNS Cache (it''s safe) Open Command Prompt as Admin.Run the following commands:ipconfig /flushdnsipconfig /releaseipconfig /renewRestart WiFi.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b1870f6e-a0fb-4b67-9910-a190a8608b40', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Why are videos stuck or repeating?', 'This may happen due to ViBe''s monitored learning system. Common reasons include: Videos must be watched fully and in sequence (no skipping).Camera and microphone permissions must be enabled.Poor lighting or high background noise can affect playback.Switching tabs or staying idle may restart the video. ✅ For smooth playback, stay on the ViBe tab, keep your camera on, and watch videos in a quiet, well-lit environment.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('736e778d-8939-46ad-9cfe-24ec65565d01', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Can I use a mobile or tablet?', 'No, only desktop/laptop is supported.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('979b7380-7ac5-44a0-8dce-c85b8311765a', '15f28d63-b183-4584-a6ae-d189b419fbea', 'I''m experiencing video issues (stuck, looping, skipping) on ViBe. How do I troubleshoot?', 'Try these troubleshooting steps in order: Refresh the page and check multiple timesInspect browser console: Right-click → Inspect → Go to Network or Console tab → Try watching the video and check for any visible errorsLog out and log in againUse a different browserClear browsing data and cache, then try to re-login If the issue persists after trying all steps, record the issue and contact Yaksha for any queries by mentioning #escalate-ViBe.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('37da8eaf-9512-4095-be34-1672a92763ca', '15f28d63-b183-4584-a6ae-d189b419fbea', 'I have completed all videos and quizzes in the ViBe course, but my progress is still showing less than 100%. What should I do?', 'Please do not worry. This might be a skip made in the quiz/video item due to penalty score as the quiz/video item might not have been successfully completed/marked. Please verify that you''ve completed all the course items (1006/1006). If not, please retry the missed contents again. In the meantime, you may try the following steps once: Refresh your browserLog out, clear your browser cache, and log in again', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7df0684b-34a0-46d8-bf7e-ba7df72cf247', '15f28d63-b183-4584-a6ae-d189b419fbea', 'I feel the ViBe content or platform is not good or I am unhappy with the way progress is evaluated. Can I request an exception or bypass the system?', 'ViBe is built and continuously improved by interns and students themselves. It is a free and open-source learning platform, and our goal is to keep it that way by encouraging the community to actively contribute, improve, and strengthen it rather than bypass it. If a learner strongly feels that the regular ViBe flow does not fairly reflect their understanding, there is a formal alternative evaluation path. However, this path is intentionally rigorous to ensure fairness for everyone. In such cases, you will be asked to: Watch the specified YouTube video content completely (links will be provided).Appear for a three-hour proctored examination based only on that content.Write the exam under strict supervision with:Two cameras (front and side view), andOne online human proctor monitoring you live. This examination becomes the sole basis for evaluation in place of the regular internship track. The scoring rules are strict: Score below 60%: You are considered not qualified and must join the next cohort and continue only through the normal ViBe mode.Score between 60% and 80%: You get one more chance in the next scheduled exam.Score above 80%: You are considered to have passed. This special exam is conducted once every fortnight, so choosing this route may significantly delay your progress compared to continuing normally on ViBe. Because this path is far more demanding and time-consuming than simply completing the regular videos, quizzes, and activities, most students find that continuing with the standard ViBe workflow is the faster and better option.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('77ea9335-8a45-4098-98a4-305ca634e4f5', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Is the ViBe consent form compulsory? What if I don''t want to grant camera access?', 'Yes — the consent form is compulsory. We would like to clearly inform you that providing consent is a mandatory requirement for any candidate enrolling in and continuing a course on the ViBe Learning Platform. The platform is designed with proctoring enabled throughout the learning process, which requires access to your webcam and microphone. This is essential to ensure: Fairness across all participantsAcademic integrityActive and genuine participation If you choose not to grant camera and microphone access, you will not be able to proceed with the course, as proctoring is an integral part of the learning and evaluation workflow. Privacy & Monitoring Clarification As outlined in the consent form: ViBe does not continuously record videos.Proctoring operates via real-time monitoring mechanisms during learning and assessments.All data is handled strictly in accordance with the stated consent terms and applicable data-protection guidelines. In short, consent is not optional — it is a core requirement for participation on the platform.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b0895b25-2d00-494f-809b-ddb1ec8c9af2', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What are penalty scores on the ViBe platform, and how do they affect our performance or HP?', 'Penalty scores are generated when anomalies are detected during your activity on the ViBe platform (for example, irregular behavior while watching video lessons or attempting quizzes). If the penalty score becomes high, you may be required to: Rewatch the video lesson, andRetake the associated quiz. At present, these penalty scores do not impact your HP (Health Points) or overall performance evaluation, as they are not being considered for scoring. Their primary purpose is to ensure proper engagement with the learning content.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d182816c-b940-40c6-ae3b-4d7a13fd6fb5', '15f28d63-b183-4584-a6ae-d189b419fbea', 'When should I use the Flag option on ViBe, and when should I contact support?', 'Use the Flag feature on ViBe only for course content-related issues, such as problems with video content or quiz questions. For technical issues, platform errors, login problems, or logistics-related queries, do not use the flag option. Instead, contact Yaksha so the team can assist you faster. Using the correct method helps resolve issues quickly and keeps the learning process smooth for everyone.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('01263e30-c1ed-473b-aacd-79575c8f6c13', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What is Linear Progression on ViBe?', 'Linear progression is enabled for every course on ViBe. This means each learner must watch the videos and attempt the quizzes in the exact order they appear on the left panel of the course page. In practice: You cannot click on a video or quiz that lies far ahead of your current position.You must complete each item before the next one unlocks.Skipping videos or quizzes is not allowed by design. Progress is sequential — finish the item in front of you, and the next one opens up automatically.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('3676f55f-476c-428d-84f0-76b742fd6e1c', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Can I use the left navigation panel to jump ahead to a later video or quiz?', 'No. Although the left navigation panel displays the full list of items in your course, it is meant only as a progress map — not as a jump-to-anywhere menu. Instead of clicking through the left panel: Click Next Quiz or Next Lesson as it appears on the right panel.Let the platform unlock items for you in sequence as you complete each one. Trying to skip ahead through the left panel will simply trigger the Access Restricted alert (see 13.13).', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('b68ddd0b-376d-4080-8823-2272d4ad7b28', '15f28d63-b183-4584-a6ae-d189b419fbea', 'I am seeing a red "Access Restricted" banner. Is this a bug?', 'No, this is not a bug. The red Access Restricted banner is an intentional alert from the platform. The banner looks like this: a red toast notification with an exclamation icon, the title "Access Restricted", and the message "Returning to previous valid content." below it. It appears when you try to open an item (video or quiz) before completing all the items that come before it. If you are on the nth item but haven''t completed every video and quiz from item 1 through item n−1, the platform will show this alert. When the banner appears, ViBe automatically returns you to the previous valid content — that is, the last item you had legitimately reached in the sequence. You will not lose any progress; you''ll simply be sent back to where you actually are in the course. It is the system gently telling you: "Please check — there is something earlier in the course that you haven''t finished yet."', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f416c4ea-8eae-4804-9ee6-464888b20a38', '15f28d63-b183-4584-a6ae-d189b419fbea', 'How do I resolve the "Access Restricted" error?', 'Follow these steps in order: Go back to the left panel and scroll through your course items from the beginning.Look for any item without a completion tick — that is your missed video or quiz.Complete that item (watch the full video, or attempt and submit the quiz).Refresh the page once you''ve completed all earlier items.If the Access Restricted banner still appears after refreshing and you are sure all earlier items are completed, report the issue to Yaksha by mentioning #escalate-ViBe. In the large majority of cases, simply finding and completing the missed item clears the alert.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4b37fd08-e44c-44f5-b8c9-8c1b0eb8c0aa', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Why does ViBe sometimes make me re-watch a clip after a quiz?', 'If your answer to the check-in quiz didn''t go through correctly, ViBe will take you back to the same clip and let you try again. This is called a re-watch, and it is part of the design — not a penalty. A few things to keep in mind: Re-watches are not recorded against you. They do not affect your HP or evaluation.The clips are short, so a re-watch usually costs less time than guessing through multiple retries.Think of the re-watch as the platform helping the idea actually stick before you move on, rather than scolding you for getting it wrong.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('fa215bca-d2ce-44e2-91b1-e213c3ad219b', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What kinds of quiz questions will I see on ViBe?', 'ViBe quizzes come in four formats: FormatWhat it looks likeWhat to doPick one (MCQ)One right answer out of four or so optionsRead all the options before clicking Pick one or more (MSQ)"Select all that apply" — could be one correct option or severalRead each option carefully; small mistakes happen here most Type a number (NAT)A text box asking for a numeric valueType just the number — no units or extra symbols, unless the question explicitly asks True or FalseA statement with only two options — True or FalseRead the statement carefully; a single word like "always," "never," or "only" can flip the correct answer A small tip: watch the clip first, then answer. Trying to read the question while the clip is still playing splits your attention.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('21bad291-6c06-431c-aa21-440770d08b75', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Are the same proctoring rules applied to every course on ViBe?', 'No — and this is one of the most important things to understand before reading the rest of this section. ViBe''s proctoring system is modular. Each individual check — face visibility, single-face-in-frame, lighting, background voices, gaze on screen, camera/microphone access — can be independently switched on or off by the instructor for a given course or cohort. This means: The instructor decides which proctoring elements are active for their course.Some courses may run with all checks active (typical for internships, faculty FDPs, and credentialed programmes).Other courses may run with only a subset active — for example, face visibility on but background-voice detection off — depending on the learning context.Certain pilot or open courses may have most proctoring relaxed, especially where the focus is exploration rather than verified evaluation. The FAQs that follow (12.18 through 12.23) describe the full set of proctoring behaviours the platform is capable of. They are written as if everything is switched on. **Whether a specific check applies to your course depends entirely on what your instructor has enabled for that course.** ⚠️ Please do not assume rules carry across courses. A relaxation given in one course (for example, allowing two faces in frame for a paired-learning module) does not transfer to another course on the same platform. Always check the course-specific guidelines shared by your instructor or programme team before each course you join. When in doubt, ask your instructor or programme coordinator which proctoring elements are active for your current course.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('e191c4c5-c75f-42b6-9d8e-d9f9040ca6fb', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What does the "quiet helper" on ViBe actually do?', 'While a lesson plays, a small helper runs gently on your device using your camera and microphone. It checks, in real time, that the basic conditions for learning are present. Specifically, it looks at five things: A face is visible — to confirm you are really there.Only one face is in frame — to confirm the learning is yours.There is enough light on your face — a silhouette is hard to recognise.The room isn''t full of voices — no talking, TV, or background podcasts.You are looking at the screen — brief glances away are fine; long stretches feel like drifting off. The helper is not a judge. Brief, normal movements (a stretch, a sneeze, a glance at your notebook) are absolutely fine. It only pays attention to sustained patterns, not split-second things.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('ea0c4301-3c7b-42ab-bd51-57f4e25b2fd5', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Does ViBe record long videos of me while I''m learning?', 'No. ViBe does not continuously record videos of you. The camera and microphone are used for real-time presence checks only.Long recordings of your face or voice are not stored.When the lesson ends, the helper goes quiet too.All data is handled strictly in accordance with the consent terms shown when you signed up. Think of the helper as a quiet study partner sitting beside you — there if needed, invisible otherwise.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('decf5074-893e-4865-8283-be81066614a6', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What is the single most common avoidable mistake learners make?', 'Sitting with a window directly behind you during the day. The room may feel bright to you, but your camera only sees a dark silhouette where your face should be. The helper then struggles to confirm your presence, and your lesson may pause or rewind. The fix is simple: move so the window is to your side or in front of the laptop, not behind you. A lamp placed in front of you works just as well in the evening.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('2e668ced-fb1b-4293-8269-d59d2fbd5346', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Why does the lesson keep pausing or restarting even when I''m paying attention?', 'If a clip keeps stopping or going back to the start, the cause is almost always something small in your environment, not the platform itself. Run through this checklist: Your face is too dark → add a lamp in front of you.Your face is partly out of frame → raise the laptop or sit a bit closer to the camera.There are voices in the background → close the door, or move to a quieter room.You switched tabs or went idle → stay on the ViBe tab; take breaks between clips, not during them.Camera or mic permission dropped → check the lock icon in your browser''s address bar and confirm both are set to "Allow".', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('99cd2633-b363-4c47-a530-3e42780b89fc', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Can I read the quiz questions aloud or mutter to myself while watching?', 'It''s best not to. The microphone listens for sustained voices in the room, and reading aloud, muttering, or asking a roommate "wait, what was that?" can all be picked up as anomalies. The simple habit is: watch in silence, answer in silence, and chat freely during your breaks between clips.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('eb133b88-f7b5-4e4d-910c-756dc139b741', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'When will I know my team details?', 'Team details are announced in the Announcements section on samagama.in. Log in and check regularly during working hours.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4ad7ab30-9238-4eb4-a1d7-2a2e39bec965', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'I received a team list email but my name is not included. What should I do?', 'Team announcements are phased, so your name may appear in a later list.If your entire cohort has moved to team activities and you are still unassigned, raise the issue on Yaksha or contact a scholar.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('880bd407-280d-4535-a093-01fd690a966a', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Can I study with a friend on camera since we''re learning together?', 'In most courses, no. Only you — the registered Learner — should be in the camera frame during a lesson. The helper checks that exactly one face is visible at a time. Group study is genuinely a wonderful habit, just not inside a ViBe session itself. A good way to do it: Hop on a separate call with your friend on your phone or a second device.Discuss concepts before or after a ViBe lesson, not during it.Return to ViBe alone when you''re ready to watch the clip and attempt the quiz. > 📌 Note: As explained in 12.17, the single-face-in-frame check is an instructor-controlled setting. A few courses (typically paired-learning or collaborative pilots) may explicitly relax this rule. Do not assume that relaxation in one course applies to another — even on the same platform with the same login. Always default to studying alone unless your instructor has clearly stated otherwise for that specific course.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4441603d-6667-4a56-bad7-7f24d5158b02', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Will I lose my progress if I clear my browser or reinstall it?', 'No. Your progress is saved on the server, tied to your registered email — not on your browser or your computer. So: Refreshing the page, clearing cache, switching browsers, or even reinstalling your browser will not wipe your progress.The moment you log back in with the same registered email, all your completed clips and quizzes will be exactly where you left them. When in doubt: log out, log back in.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('0f4c4547-fef0-478e-9a72-d77f268a5fb0', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'How will communication happen within teams?', 'Teams self-organise internal coordination over LinkedIn or email only, limited to their own team members. WhatsApp is not encouraged for team coordination — and it is not permitted to create a team WhatsApp group (a four-person project team is still a "subset of interns", which is prohibited under §6.1; a group of that form, if reported, will lead to immediate termination of the internship). Official programme updates continue to come through the Announcements section on samagama.in and Yaksha chat — see §6.1 for the full communication policy.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('ca3155fe-74c7-488b-9bb4-295b573e7c77', '15f28d63-b183-4584-a6ae-d189b419fbea', 'Is there a recommended daily learning rhythm on ViBe?', 'Yes — small, regular sessions work far better than long marathon sessions. A practical rhythm: Show up daily, even if only for thirty minutes. Daily consistency beats a five-hour weekend cram.Take breaks between clips, not during them. A clip is short — finish it first.Treat each quiz as a gentle check-in, not a high-stakes test.For programmes with deadlines (such as internships or faculty cohorts), aim for the daily progress target announced by your programme team — typically around 3.33% per day. > 📌 A note on milestones: The pacing above is a general guideline only. For any specific programme (Vinternship cohort, faculty FDP, NPTEL internship, institutional pilot, etc.), the actual milestones, deadlines, and weekly progress targets will be announced by your instructors or programme team. Always follow the milestone schedule communicated for your specific cohort — that takes precedence over the general guidance here.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('0d736fb9-aa77-4d77-aa9f-271eeb8af190', '15f28d63-b183-4584-a6ae-d189b419fbea', 'What should my "study corner" look like before I start a ViBe session?', 'A ViBe-friendly study spot needs only three things: Light in front of your face — a lamp or window facing you, never behind.Just you in the camera frame — ask family, friends, or pets not to wander through.A reasonably quiet room — no TV, no music with words, no one else on a call nearby. Two minutes of setup before you start saves a lot of small frustrations during the lesson.', '{"vibe"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('02b0a720-ca13-4ab7-a482-0f6806631724', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Is team formation compulsory?', 'Yes. All projects in Phase 2 and Phase 3 (some parts) must be completed in teams. Every participant is required to be part of a team.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('c6da9c59-fb72-4681-8129-39b5594d63ae', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What is the size of a team?', 'The team size is fixed at four members. This is mandatory — you cannot have fewer or more members in a team at the time of final formation.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('c66228a0-aa2f-44f8-82f0-c3a6a6926290', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'How are teams formed?', 'For students who joined on May 15 and 16: Teams were formed through a structured activity.For students joining later: Teams will be randomly assigned by the administration.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('7738bda4-1091-42f6-9c41-c50445736dcd', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'I started on May 15/16 but couldn''t form a team during the activity. What happens now?', 'You will be randomly assigned to a team.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('4e12455b-8d7f-46a5-8ada-a5159c9916ce', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'There was a typo in our email addresses during team formation. Can we fix it?', 'No action is required from your side. The administration will verify and match email IDs with names before finalizing and locking teams.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('e95b4adc-b639-426c-842e-3ab9942c5fc9', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'I formed a team with only two members. Will it be considered?', 'No. Teams with fewer than four members will be expanded by adding additional members to make a final team of four.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('f854cc88-057b-4ca7-95c2-03300e27d05a', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What if a team member leaves or becomes ineligible during Phase 1?', 'The administration will attempt to assign a replacement member.If no replacement is found, you may continue as a team of three.You must inform the admin immediately, or the change will not be recognized.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('d2acfe2e-2d0f-419d-a97b-03fbf2d550db', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can I form a team with someone from my own college?', 'No. Teams must consist of members from different institutions to encourage networking. Exception: Students from the same institution but different campuses/locations may be allowed.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('c6c2e3fc-b6c6-49b1-b4d9-33eac33d7262', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can I form a team with students from my IIT MBS cohort?', 'No. You are encouraged to collaborate with participants outside your existing cohort.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('0259be85-6e22-4f24-9e85-3f6b338f4b91', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can we change our team name after submission?', 'Yes, team names are tentative and can be changed. However, due to operational constraints, frequent changes are discouraged.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('c68e8a96-ea8b-41f0-a4ba-85e621ed97a1', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What if multiple teams choose the same name?', 'Teams will be distinguished using suffixes (e.g., Team X-1, Team X-2, etc.).', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('53e8ffce-833b-4289-82c7-d40df1063fb6', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'I just started the internship. Can I form my own team now?', 'No. For later cohorts, teams will be randomly assigned. Please wait for the official communication.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('87e6ada6-62d7-4025-8175-7e2b36bac80b', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'When do team activities begin?', 'Team-based work begins in Phase 2. During Phase 1 (online coursework), you do not need to worry about team activities.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('5bd59779-9923-424e-befa-a60f7b7e6c8b', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'Can I request a specific teammate after teams are assigned?', 'No. Team assignments are final and requests for changes are not entertained.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public.faqs (id, category_id, question, answer, tags, view_count, upvotes, downvotes, search_count, priority_score, is_published, created_at, updated_at) VALUES ('fc2a7d7b-96fc-4958-a21c-79128c077c4b', 'af05cb5e-a803-41af-b387-b29046ae20c6', 'What happens if a team member is inactive or not contributing?', 'You should report the issue to your mentor/scholar early. Prolonged inactivity may lead to administrative intervention.', '{"team"}', 0, 0, 0, 0, 0, true, '2026-07-08T04:56:56.09136+00:00', '2026-07-08T04:59:34.489552+00:00') ON CONFLICT DO NOTHING;
